IF OBJECT_ID('pumpui_sync_log', 'U') IS NULL
BEGIN
    CREATE TABLE pumpui_sync_log (
        SyncID INT IDENTITY(1,1) PRIMARY KEY,
        SyncDate DATETIME DEFAULT GETDATE(),
        NewRecords INT,
        ModifiedRecords INT,
        TotalRecords INT,
        errorDetails NVARCHAR(MAX)
    );
END
ELSE
BEGIN
    IF COL_LENGTH('pumpui_sync_log', 'errorDetails') IS NULL
    BEGIN
        ALTER TABLE pumpui_sync_log ADD errorDetails NVARCHAR(MAX);
    END
END

DECLARE @ModifiedDetails TABLE (
    OrderID VARCHAR(50),
    CustomerName NVARCHAR(255),
    ProductName NVARCHAR(255),
    OldNetAmount FLOAT,
    NewNetAmount FLOAT,
    OldQuantity INT,
    NewQuantity INT,
    OldPrice FLOAT,
    NewPrice FLOAT
);

INSERT INTO @ModifiedDetails
SELECT 
    e.OrderID,
    e.CustomerName,
    e.ProductName,
    s.NetAmount AS OldNetAmount,
    e.NetAmount AS NewNetAmount,
    s.Quantity AS OldQuantity,
    e.Quantity AS NewQuantity,
    s.Price AS OldPrice,
    e.Price AS NewPrice
FROM pumpui_erp e
INNER JOIN pumpui_show s ON s.OrderID = e.OrderID
WHERE s.NetAmount <> e.NetAmount OR s.Quantity <> e.Quantity OR s.Price <> e.Price;

DECLARE @new_count INT;
DECLARE @mod_count INT;
DECLARE @total_count INT;
DECLARE @error_count INT;
DECLARE @error_details_str NVARCHAR(MAX);

SELECT @new_count = COUNT(*) 
FROM pumpui_erp e
WHERE NOT EXISTS (SELECT 1 FROM pumpui_show s WHERE s.OrderID = e.OrderID);

SELECT @mod_count = COUNT(*) FROM @ModifiedDetails;

SELECT @total_count = COUNT(*) FROM pumpui_erp;

DECLARE @ErrorOrderIDs TABLE (OrderID VARCHAR(50));
INSERT INTO @ErrorOrderIDs
SELECT OrderID FROM pumpui_erp
WHERE OrderID IS NULL OR OrderDate IS NULL OR CustomerID IS NULL OR ProductID IS NULL OR NetAmount IS NULL OR NetAmount < 0 OR Quantity IS NULL OR Quantity < 0 OR Price IS NULL OR Price < 0 OR Region IS NULL OR Region = '' OR ProvinceID IS NULL OR ProvinceID = '' OR Province IS NULL OR Province = '';

SELECT @error_count = COUNT(*) FROM @ErrorOrderIDs;

DECLARE @Top5 NVARCHAR(MAX);
SET @Top5 = '';

SELECT @Top5 = COALESCE(@Top5 + ', ', '') + OrderID
FROM (
    SELECT TOP 5 OrderID FROM @ErrorOrderIDs ORDER BY OrderID
) t;

IF LEN(@Top5) > 2
BEGIN
    SET @Top5 = SUBSTRING(@Top5, 3, LEN(@Top5) - 2);
END

IF @error_count > 5
BEGIN
    DECLARE @remaining INT;
    SET @remaining = @error_count - 5;
    SET @error_details_str = @Top5 + N' (และอีก ' + CAST(@remaining AS NVARCHAR(50)) + N' รายการ)';
END
ELSE
BEGIN
    SET @error_details_str = @Top5;
END

-- Use sp_executesql to avoid compile-time \"Invalid column name 'errorDetails'\" error
EXEC sp_executesql 
    N'INSERT INTO pumpui_sync_log (SyncDate, NewRecords, ModifiedRecords, TotalRecords, errorDetails) VALUES (GETDATE(), @new, @mod, @total, @errDetails)',
    N'@new INT, @mod INT, @total INT, @errDetails NVARCHAR(MAX)',
    @new = @new_count,
    @mod = @mod_count,
    @total = @total_count,
    @errDetails = @error_details_str;

DELETE FROM pumpui_show_fact;
DELETE FROM pumpui_show_dim_customer;
DELETE FROM pumpui_show_dim_product;
DELETE FROM pumpui_show_dim_geography;

INSERT INTO pumpui_show_dim_geography (ProvinceID, Province, Region)
SELECT DISTINCT ProvinceID, Province, Region
FROM pumpui_erp
WHERE OrderID IS NOT NULL AND OrderDate IS NOT NULL AND CustomerID IS NOT NULL AND ProductID IS NOT NULL AND NetAmount IS NOT NULL AND NetAmount >= 0 AND Quantity IS NOT NULL AND Quantity >= 0 AND Price IS NOT NULL AND Price >= 0 AND Region IS NOT NULL AND Region <> '' AND ProvinceID IS NOT NULL AND ProvinceID <> '' AND Province IS NOT NULL AND Province <> '';

INSERT INTO pumpui_show_dim_customer (CustomerID, CustomerName, CustomerType)
SELECT DISTINCT CustomerID, CustomerName, CustomerType
FROM pumpui_erp
WHERE OrderID IS NOT NULL AND OrderDate IS NOT NULL AND CustomerID IS NOT NULL AND ProductID IS NOT NULL AND NetAmount IS NOT NULL AND NetAmount >= 0 AND Quantity IS NOT NULL AND Quantity >= 0 AND Price IS NOT NULL AND Price >= 0 AND Region IS NOT NULL AND Region <> '' AND ProvinceID IS NOT NULL AND ProvinceID <> '' AND Province IS NOT NULL AND Province <> '';

INSERT INTO pumpui_show_dim_product (ProductID, ProductName, ProductCategory)
SELECT DISTINCT ProductID, ProductName, ProductCategory
FROM pumpui_erp
WHERE OrderID IS NOT NULL AND OrderDate IS NOT NULL AND CustomerID IS NOT NULL AND ProductID IS NOT NULL AND NetAmount IS NOT NULL AND NetAmount >= 0 AND Quantity IS NOT NULL AND Quantity >= 0 AND Price IS NOT NULL AND Price >= 0 AND Region IS NOT NULL AND Region <> '' AND ProvinceID IS NOT NULL AND ProvinceID <> '' AND Province IS NOT NULL AND Province <> '';

INSERT INTO pumpui_show_fact (OrderID, OrderDate, CustomerID, ProductID, ProvinceID, Price, Quantity, NetAmount)
SELECT OrderID, OrderDate, CustomerID, ProductID, ProvinceID, Price, Quantity, NetAmount
FROM pumpui_erp
WHERE OrderID IS NOT NULL AND OrderDate IS NOT NULL AND CustomerID IS NOT NULL AND ProductID IS NOT NULL AND NetAmount IS NOT NULL AND NetAmount >= 0 AND Quantity IS NOT NULL AND Quantity >= 0 AND Price IS NOT NULL AND Price >= 0 AND Region IS NOT NULL AND Region <> '' AND ProvinceID IS NOT NULL AND ProvinceID <> '' AND Province IS NOT NULL AND Province <> '';

DECLARE @Inserted INT = @@ROWCOUNT;

UPDATE pumpui_show_dim_customer
SET CustomerName = LEFT(CustomerName, 4) + '***'
WHERE CustomerName IS NOT NULL;

DECLARE @ErrorCount INT = (SELECT COUNT(*) FROM pumpui_erp WHERE NetAmount IS NULL OR ProvinceID IS NULL OR Province IS NULL);

SELECT @Inserted AS rowsInserted, @ErrorCount AS rowsError;

